export const  SCRIPT_SUFFIX = `chatForm.addEventListener('submit',e=>{
  e.preventDefault();
  const q=chatInput.value.trim();
  if(!q)return;
  // User message
  const um=document.createElement('div');
  um.className='chat-msg user';um.textContent=q;
  chatMessages.appendChild(um);
  chatInput.value='';
  chatMessages.scrollTop=chatMessages.scrollHeight;
  // Typing indicator
  const ti=document.createElement('div');
  ti.className='chat-msg bot typing';ti.textContent='Thinking...';
  chatMessages.appendChild(ti);
  chatMessages.scrollTop=chatMessages.scrollHeight;
  // Bot reply after brief delay
  setTimeout(()=>{
    ti.remove();
    const bm=document.createElement('div');
    bm.className='chat-msg bot';
    bm.innerHTML=botReply(q).replace(/\\*\\*(.*?)\\*\\*/g,'<strong>$1</strong>');
    chatMessages.appendChild(bm);
    chatMessages.scrollTop=chatMessages.scrollHeight;
  },600+Math.random()*400);
});
`
